 20→
 21→
 22→class ErrorBoundary extends React.Component {
 23→  state = { error: null };
 24→  static getDerivedStateFromError(error) {
 25→    return { error };
 26→  }
 27→  render() {
 28→    if (this.state.error) {
 29→      return <div>Error: {this.state.error.message}</div>;
 30→    }
 31→    return this.props.children;
 32→  }
 33→}
 34→
 35→/* theme for mapping css classes to lexical rols */
 36→const theme = {
 37→    paragraph: 'editor-paragraph',
 38→    heading: 'editor-heading',
 39→}
 40→
 41→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null}) => {
 42→    const [editor] = useLexicalComposerContext();
 43→    const [editorState, setEditorState] = useState(null);
 44→    const [hasContent, setHasContent] = useState(false);
 45→    const [isSending, setIsSending] = useState(false);
 46→
 47→    const {session, user} = useAuth();
 48→
 49→    const queryClient = useQueryClient();
 50→
 51→    const handleClickSave = async(e, title) =>{
 52→        e.stopPropagation();
 53→        setIsSending(true)
 54→        try {
 55→            const formdata = new FormData();
 56→            if(title && editorState){
 57→                formdata.append('title', title)
 58→                formdata.append('content', editorState)
 59→            }
 60→            if(promptId){
 61→                formdata.append('prompt_id', promptId);
 62→            }
 63→            const saveData = await saveJournal(session?.access_token, formdata)
 64→
 65→            if(saveData){
 66→                // console.log(saveData)
 67→                queryClient.invalidateQueries({queryKey: ['journals']});
 68→                queryClient.invalidateQueries({queryKey: ['userJournals', user?.userData?.[0].id]})
 69→                queryClient.invalidateQueries({queryKey: ['streak', user?.userData?.[0]?.id]});
 70→            }
 71→
 72→            setIsSending(false)
 73→        } catch (error) {
 74→            console.error("Error saving journal:", error);
 75→        }finally {
 76→            setIsSending(false)
 77→            setHasContent(false)
 78→            onCloseOnSave();
 79→            addUploadImagesPath([])
 80→        }
 81→
 82→    }
 83→
 84→    const onchange = useCallback((state) => {
 85→        const jsonb = JSON.stringify(state.toJSON());
 86→        setEditorState(jsonb)
 87→
 88→        state.read(() => {
 89→            const root = $getRoot();
 90→
 91→            const children = root.getChildren();
 92→
 93→            const hasEnoughParagraphNodes = children.length > 1
 94→            const hasParargraphSize = children[0]?.__size > 0
 95→
 96→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
 97→            setHasContent(hasContent);
 98→
 99→            // Calculate word count
100→            const text = root.getTextContent().trim();
101→            const words = text ? text.split(/\s+/).length : 0;
102→            setWordCount(words);
103→        })
104→    }, [setWordCount])
105→
106→    return(
107→        <>
108→        {/* Toolbar above content */}
109→        <div className="toolbar-wrapper">
110→            <ToolBar addUploadedImagePath={addUploadImagesPath}/>
111→        </div>
112→
113→        {/* Bar loader directly under toolbar */}
114→        <div className="editor-loader-wrapper">
115→            {isSending && (
116→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
117→            )}
118→        </div>
119→
120→        {/* Editor content area */}
121→        <div className="editor-shell">
122→            <RichTextPlugin
123→            contentEditable={
124→            <ContentEditable
125→            className="editor-input"
126→            aria-placeholder="Write your thoughts here..."
127→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
128→            }
129→            ErrorBoundary={LexicalErrorBoundary}
130→            />
131→
132→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
133→            <MentionPlugin/>
134→            <HistoryPlugin/>
135→            <OnChangePlugin onChange={onchange}/>
136→
137→        </div>
138→
139→        {/* Footer: word count + save */}
140→        <div className='editor-footer'>
141→            <span className="editor-word-count">
142→                {wordCount} {wordCount === 1 ? 'word' : 'words'}
143→            </span>
144→            <button disabled={!title || !hasContent || isSending} onClick={(e) =>handleClickSave(e, title)} className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}>
145→                Share
146→            </button>
147→        </div>
148→        </>
149→    )
150→}
151→
152→export default EditorInner;
