 29→    //heading node (H1, H2, H3)
 30→    const setHeading = (tag) => {
 31→        editor.update(() => {
 32→            const selection = $getSelection();
 33→            if ($isRangeSelection(selection)) {
 34→                const anchorNode = selection.anchor.getNode();
 35→                
 36→                let element;
 37→                try {
 38→                    element = anchorNode.getKey() === 'root' //checking if anchorNode itselt is the root
 39→                        ? anchorNode  //if not then use getTopLevelElement() method first then as a fallback use getTopLevelElementOrThrow() method
 40→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
 41→                } catch (e) {
 42→                    console.error('Could not get top level element:', e);
 43→                    return;
 44→                }
 45→
 46→                if (!element) return;
 47→
 48→                const type = typeof element.getType === 'function' ? element.getType() : null; //check if elements have getType() === function sometimes nodes dont have getType
 49→                // console.log('Element type:', type);
 50→
 51→                if (type && type !== "paragraph" && type !== "heading") { //only proceed if element is paragraph or heading
 52→                    return;
 53→                }
 54→
 55→                const isActive = $isHeadingNode(element) && element.getTag() === tag; //checking if element.getTag() === 'tag. returns a boolean
 56→
 57→                //use $setBlocksType to change the block type
 58→                //return paragraph if already active(toggle back) otherwise create heading
